using CourseCatalog.Models;

namespace CourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = "MATH", Name = "Mathematics", Description = "Pure and applied mathematics, statistics, and data analysis." },
        new() { Id = "ENG", Name = "English", Description = "Literature, writing, and communication studies." },
        new() { Id = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Id = "HIST", Name = "History", Description = "Analysis of past events and their impact on modern society." },
    ];

    private readonly List<Course> _courses =
    [
        new()
        {
            Id = 1, Code = "CS 101", Title = "Introduction to Programming",
            Description = "Learn the fundamentals of programming using Python. Topics include variables, control structures, functions, and basic data structures. No prior experience required.",
            Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = "CS",
            InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses. She holds a Ph.D. from MIT and specializes in CS education research.",
            IsFeatured = true
        },
        new()
        {
            Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms",
            Description = "Study of fundamental data structures (lists, trees, graphs, hash tables) and algorithm design techniques (divide-and-conquer, dynamic programming, greedy algorithms).",
            Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM", DepartmentId = "CS",
            InstructorName = "Dr. James Liu", InstructorBio = "Dr. Liu is an ACM Distinguished Educator with research in algorithm optimization. Previously worked at Google Research.",
            IsFeatured = true
        },
        new()
        {
            Id = 3, Code = "CS 310", Title = "Database Systems",
            Description = "Relational database design, SQL, normalization, transaction processing, and introduction to NoSQL systems.",
            Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", DepartmentId = "CS",
            InstructorName = "Prof. Maria Santos", InstructorBio = "Prof. Santos spent a decade in industry at Oracle and Amazon before joining academia. Her research focuses on distributed database systems.",
            IsFeatured = false
        },
        new()
        {
            Id = 4, Code = "MATH 151", Title = "Calculus I",
            Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems.",
            Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = "MATH",
            InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator known for making calculus accessible. Author of 'Calculus Without Tears'.",
            IsFeatured = true
        },
        new()
        {
            Id = 5, Code = "MATH 250", Title = "Linear Algebra",
            Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications to data science.",
            Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", DepartmentId = "MATH",
            InstructorName = "Dr. Emily Park", InstructorBio = "Dr. Park's research bridges pure mathematics and machine learning. She previously held a postdoctoral position at Stanford.",
            IsFeatured = false
        },
        new()
        {
            Id = 6, Code = "ENG 101", Title = "Academic Writing",
            Description = "Develop clear, persuasive writing skills for academic contexts. Emphasis on thesis development, evidence-based argumentation, and revision strategies.",
            Credits = 3, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentId = "ENG",
            InstructorName = "Prof. David Thompson", InstructorBio = "Prof. Thompson is a published author and writing coach with 20 years of teaching experience at the university level.",
            IsFeatured = false
        },
        new()
        {
            Id = 7, Code = "ENG 220", Title = "American Literature",
            Description = "Survey of American literature from the colonial period to the present. Examines major works in their historical and cultural contexts.",
            Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", DepartmentId = "ENG",
            InstructorName = "Dr. Angela Morris", InstructorBio = "Dr. Morris specializes in 20th-century American fiction. Her book on Toni Morrison won the 2019 Modern Language Association prize.",
            IsFeatured = true
        },
        new()
        {
            Id = 8, Code = "PHYS 101", Title = "General Physics I",
            Description = "Mechanics, thermodynamics, and waves. Calculus-based introduction to classical physics with weekly lab sessions.",
            Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Thu Lab 2:00–4:00 PM", DepartmentId = "PHYS",
            InstructorName = "Dr. Alan Foster", InstructorBio = "Dr. Foster is a former NASA researcher whose work contributed to the Mars rover missions. He brings real-world physics applications to the classroom.",
            IsFeatured = false
        },
        new()
        {
            Id = 9, Code = "PHYS 301", Title = "Quantum Mechanics",
            Description = "Introduction to quantum theory: wave functions, Schrödinger equation, angular momentum, spin, and hydrogen atom.",
            Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", DepartmentId = "PHYS",
            InstructorName = "Dr. Priya Patel", InstructorBio = "Dr. Patel is a theoretical physicist whose research in quantum computing has been published in Nature and Physical Review Letters.",
            IsFeatured = false
        },
        new()
        {
            Id = 10, Code = "HIST 101", Title = "World History to 1500",
            Description = "Survey of major civilizations, cultural exchanges, and transformative events from prehistory through the late medieval period.",
            Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", DepartmentId = "HIST",
            InstructorName = "Dr. Michael Okafor", InstructorBio = "Dr. Okafor is a specialist in comparative world history with fieldwork experience across three continents. He emphasizes primary source analysis.",
            IsFeatured = false
        },
    ];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(string id) =>
        _departments.FirstOrDefault(d => d.Id.Equals(id, StringComparison.OrdinalIgnoreCase));

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() =>
        _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(string departmentId) =>
        _courses.Where(c => c.DepartmentId.Equals(departmentId, StringComparison.OrdinalIgnoreCase)).ToList();

    public Course? GetCourse(int id) =>
        _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? query, string? departmentId)
    {
        var results = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentId))
        {
            results = results.Where(c => c.DepartmentId.Equals(departmentId, StringComparison.OrdinalIgnoreCase));
        }

        if (!string.IsNullOrWhiteSpace(query))
        {
            var q = query.Trim();
            results = results.Where(c =>
                c.Title.Contains(q, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(q, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(q, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(q, StringComparison.OrdinalIgnoreCase));
        }

        return results.ToList();
    }
}

