<h1>Enrollment Request</h1>
<p>Fill out this form to request enrollment in a course. You will receive a confirmation via your university email.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Thank you, <strong>@Model.FullName</strong>. Your enrollment request for
           <strong>@(selectedCourseName)</strong> has been received.
           You will receive a confirmation at your university email.</p>
        <a href="enroll" class="btn btn-outline-success">Submit Another Request</a>
        <a href="courses" class="btn btn-outline-primary ms-2">Back to Courses</a>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment" method="post">
        <DataAnnotationsValidator />
        <AntiforgeryToken />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="fullName" class="form-label">Full Name</label>
            <InputText id="fullName" class="form-control" @bind-Value="Model.FullName" />
            <ValidationMessage For="() => Model.FullName" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" placeholder="e.g., CS123456" />
            <ValidationMessage For="() => Model.StudentId" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                <option value="0">-- Select a course --</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id">@course.Code - @course.Title (@course.Credits cr)</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.CourseId" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
        <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery(Name = "courseId")]
    private int? PreselectedCourseId { get; set; }

    private List<Course> courses = [];
    private bool submitted;
    private string selectedCourseName = "";

    protected override void OnInitialized()
    {
        courses = Catalog.GetAllCourses();

        if (PreselectedCourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = PreselectedCourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        var course = Catalog.GetCourse(Model.CourseId);
        selectedCourseName = course is not null ? $"{course.Code} - {course.Title}" : "Unknown";
        submitted = true;
    }
}
