@page "/courses"
@using CourseCatalog.Models
@using CourseCatalog.Services
@rendermode InteractiveServer
@inject CatalogService Catalog

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
               @bind="searchQuery" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="selectedDepartment">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
</div>

@if (filteredCourses.Count == 0)
{
    <p class="text-muted">No courses match your search criteria.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in filteredCourses)
            {
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentId</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

<p class="text-muted">Showing @filteredCourses.Count of @allCourses.Count courses</p>

@code {
    private List<Department> departments = [];
    private List<Course> allCourses = [];
    private List<Course> filteredCourses = [];

    private string _searchQuery = "";
    private string _selectedDepartment = "";

    private string searchQuery
    {
        get => _searchQuery;
        set { _searchQuery = value; ApplyFilters(); }
    }

    private string selectedDepartment
    {
        get => _selectedDepartment;
        set { _selectedDepartment = value; ApplyFilters(); }
    }

    [SupplyParameterFromQuery(Name = "department")]
    private string? InitialDepartment { get; set; }

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        allCourses = Catalog.GetAllCourses();

        if (!string.IsNullOrWhiteSpace(InitialDepartment))
        {
            _selectedDepartment = InitialDepartment;
        }

        ApplyFilters();
    }

    private void ApplyFilters()
    {
        filteredCourses = Catalog.SearchCourses(
            string.IsNullOrWhiteSpace(_searchQuery) ? null : _searchQuery,
            string.IsNullOrWhiteSpace(_selectedDepartment) ? null : _selectedDepartment);
    }
}

