@page "/courses/{Id:int}"
@using CourseCatalog.Models
@using CourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

@if (course is null)
{
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="courses" class="btn btn-primary">Back to Courses</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item"><a href="courses?department=@course.DepartmentId">@departmentName</a></li>
            <li class="breadcrumb-item active">@course.Code</li>
        </ol>
    </nav>

    <h1>@course.Code &mdash; @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h2>Description</h2>
            <p>@course.Description</p>

            <h2>Schedule</h2>
            <p><strong>@course.Schedule</strong></p>

            <h2>Credits</h2>
            <p><span class="badge bg-primary fs-6">@course.Credits credits</span></p>
        </div>

        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Instructor</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.InstructorName</h6>
                    <p class="card-text">@course.InstructorBio</p>
                </div>
            </div>

            <div class="mt-3">
                <a href="enroll?courseId=@course.Id" class="btn btn-success w-100">Enroll in This Course</a>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? course;
    private string departmentName = "";

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
        if (course is not null)
        {
            var dept = Catalog.GetDepartment(course.DepartmentId);
            departmentName = dept?.Name ?? course.DepartmentId;
        }
    }
}

